SELECT casrn, molecular_weight, AVG(value) as avg_value, MAX(time) as latest_time
FROM compounds
WHERE compound_id = 1;

SELECT name
FROM compound_sets
WHERE set_id = 0;

SELECT COUNT(compound_id) AS compound_count
FROM compound_set_compounds
WHERE set_id = 1;

SELECT COUNT(compound_id) AS compound_count
FROM categories_compounds
WHERE category_id = 0;
